function o(e,s="success"){const t=document.createElement("div");t.className=`
    fixed bottom-4 left-1/2 transform -translate-x-1/2
    px-4 py-2 rounded shadow-lg z-50
    text-white text-sm font-medium
    ${s==="success"?"bg-green-600":"bg-red-600"}
  `,t.textContent=e,document.body.appendChild(t),setTimeout(()=>{t.classList.add("opacity-0"),setTimeout(()=>t.remove(),500)},3e3)}export{o as s};
